import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;

import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly handle user input by encoding it before including in the response
        File file = new File("output.html");
        try (PrintWriter out = new PrintWriter(file)) {
            out.println("<html>");
            out.println("<body>");
            out.println("<p>User Input: " + Encode.forHtml(userInput) + "</p>");
            out.println("</body>");
            out.println("</html>");
        }

        System.out.println("Output written to output.html.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
